mapper.select:
SELECT id, title, summary, category, tags, likes_count as likesCount, plays_count as playsCount, user_nickname as userNickname, user_avatar as userAvatar, created_at as createdAt FROM community_stories WHERE status = 1
AND category = #{category}
ORDER BY
likes_count DESC, plays_count DESC
created_at DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE community_stories
SET plays_count = plays_count + 1
WHERE id = #{id}

UPDATE community_stories
SET likes_count = likes_count + 1
WHERE id = #{id}
